INSERT INTO "_prisma_migrations" (id, checksum, finished_at, migration_name, logs, rolled_back_at, started_at, applied_steps_count) SELECT gen_random_uuid()::text, 'baseline', NOW(), migration_name, NULL, NULL, NOW(), 1 FROM (VALUES ('20250101000000_baseline'),('20260101175059_init_pos'),('20260315093000_dynamic_mix_preparation'),('20260316092000_mix_batch_costing_phase1'),('20260325120000_weighted_avg_costing'),('20260326091500_finance_perf_indexes'),('20260328000001_cash_locations_system')) AS t(migration_name) WHERE NOT EXISTS (SELECT 1 FROM "_prisma_migrations" WHERE "_prisma_migrations".migration_name = t.migration_name);
